void test_smoke_streaming_openai(void) {
    /* Chat streaming against real OpenAI API, verifies chunks received */
    const char* api_key = getenv("OPENAI_API_KEY");
    const char* mock_base = getenv("MOCK_SERVER_URL");
    char base_url_buf[512];
    int use_mock = !(api_key && api_key[0] != '\0');
    if (!use_mock) {
        fprintf(stderr, "smoke_streaming_openai: using real API (OPENAI_API_KEY is set)\n");
    } else {
        fprintf(stderr, "smoke_streaming_openai: using mock server (OPENAI_API_KEY not set)\n");
        snprintf(base_url_buf, sizeof(base_url_buf), "%s/fixtures/smoke_streaming_openai", mock_base ? mock_base : "");
        api_key = "test-key";
    }
    LITERLLMChatCompletionRequest* chat_completion_request_handle = literllm_chat_completion_request_from_json("{\"max_tokens\":50,\"messages\":[{\"content\":\"Count from 1 to 5.\",\"role\":\"user\"}],\"model\":\"openai/gpt-4o-mini\"}");
    assert(chat_completion_request_handle != NULL && "failed to build request");
    const char* _base_url_arg = use_mock ? base_url_buf : NULL;
    LITERLLMDefaultClient* client = literllm_create_client(api_key, _base_url_arg, (uint64_t)-1, (uint32_t)-1, NULL);
    assert(client != NULL && "failed to create client");
    LITERLLMLiterllmDefaultClientChatStreamStreamHandle* stream_handle = literllm_default_client_chat_stream_start(client, chat_completion_request_handle);
    assert(stream_handle != NULL && "expected stream-start to succeed");
    size_t chunks_count = 0;
    char* stream_content = (char*)malloc(1);
    assert(stream_content != NULL);
    stream_content[0] = '\0';
    size_t stream_content_len = 0;
    int stream_complete = 0;
    int no_chunks_after_done = 1;
    char* last_choices_json = NULL;
    uint64_t total_tokens = 0;

    while (1) {
        LITERLLMChatCompletionChunk* result = literllm_default_client_chat_stream_next(stream_handle);
        if (result == NULL) {
            if (literllm_last_error_code() == 0) { stream_complete = 1; }
            break;
        }
        chunks_count++;
        char* choices_json = literllm_chat_completion_chunk_choices(result);
        if (choices_json != NULL) {
            const char* d = strstr(choices_json, "\"content\":");
            if (d != NULL) {
                d += 10;
                while (*d == ' ' || *d == '\t') d++;
                if (*d == '"') {
                    d++;
                    const char* e = d;
                    while (*e && *e != '"') {
                        if (*e == '\\' && *(e+1)) e += 2; else e++;
                    }
                    size_t add = (size_t)(e - d);
                    if (add > 0) {
                        char* nc = (char*)realloc(stream_content, stream_content_len + add + 1);
                        if (nc != NULL) {
                            stream_content = nc;
                            memcpy(stream_content + stream_content_len, d, add);
                            stream_content_len += add;
                            stream_content[stream_content_len] = '\0';
                        }
                    }
                }
            }
            if (last_choices_json != NULL) literllm_free_string(last_choices_json);
            last_choices_json = choices_json;
        }
        LITERLLMUsage* usage_handle = literllm_chat_completion_chunk_usage(result);
        if (usage_handle != NULL) {
            total_tokens = (uint64_t)literllm_usage_total_tokens(usage_handle);
            literllm_usage_free(usage_handle);
        }
        literllm_chat_completion_chunk_free(result);
    }
    literllm_default_client_chat_stream_free(stream_handle);

    char* finish_reason = NULL;
    char* tool_calls_json = NULL;
    char* tool_calls_0_function_name = NULL;
    if (last_choices_json != NULL) {
        finish_reason = alef_json_get_string(last_choices_json, "finish_reason");
        const char* tc = strstr(last_choices_json, "\"tool_calls\":");
        if (tc != NULL) {
            tc += 13;
            while (*tc == ' ' || *tc == '\t') tc++;
            if (*tc == '[') {
                int depth = 0;
                const char* end = tc;
                int in_str = 0;
                for (; *end; end++) {
                    if (*end == '\\' && in_str) { if (*(end+1)) end++; continue; }
                    if (*end == '"') { in_str = !in_str; continue; }
                    if (in_str) continue;
                    if (*end == '[' || *end == '{') depth++;
                    else if (*end == ']' || *end == '}') { depth--; if (depth == 0) { end++; break; } }
                }
                size_t tlen = (size_t)(end - tc);
                tool_calls_json = (char*)malloc(tlen + 1);
                if (tool_calls_json != NULL) {
                    memcpy(tool_calls_json, tc, tlen);
                    tool_calls_json[tlen] = '\0';
                    const char* fn = strstr(tool_calls_json, "\"function\"");
                    if (fn != NULL) {
                        const char* np = strstr(fn, "\"name\":");
                        if (np != NULL) {
                            np += 7;
                            while (*np == ' ' || *np == '\t') np++;
                            if (*np == '"') {
                                np++;
                                const char* ne = np;
                                while (*ne && *ne != '"') { if (*ne == '\\' && *(ne+1)) ne += 2; else ne++; }
                                size_t nlen = (size_t)(ne - np);
                                tool_calls_0_function_name = (char*)malloc(nlen + 1);
                                if (tool_calls_0_function_name != NULL) {
                                    memcpy(tool_calls_0_function_name, np, nlen);
                                    tool_calls_0_function_name[nlen] = '\0';
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    assert(chunks_count >= 1 && "expected at least 1 chunks");
    free(stream_content);
    if (last_choices_json != NULL) literllm_free_string(last_choices_json);
    if (finish_reason != NULL) free(finish_reason);
    if (tool_calls_json != NULL) free(tool_calls_json);
    if (tool_calls_0_function_name != NULL) free(tool_calls_0_function_name);
    literllm_chat_completion_request_free(chat_completion_request_handle);
    literllm_default_client_free(client);
    /* suppress unused */ (void)total_tokens; (void)no_chunks_after_done; (void)stream_complete; (void)chunks_count; (void)stream_content_len;
}

void test_vertex_chat(void) {
    /* Basic chat completion via the Google Vertex AI provider using the vertex_ai/ prefix for routing — verifies the prefix is stripped before dispatching and the Gemini response is normalised to the standard OpenAI chat completion shape */
    LITERLLMChatCompletionRequest* chat_completion_request_handle = literllm_chat_completion_request_from_json("{\"max_tokens\":16,\"messages\":[{\"content\":\"Say hello in one word.\",\"role\":\"user\"}],\"model\":\"vertex_ai/gemini-2.0-flash\",\"temperature\":0}");
    assert(chat_completion_request_handle != NULL && "failed to build request");
    const char* mock_base = getenv("MOCK_SERVER_URL");
    assert(mock_base != NULL && "MOCK_SERVER_URL must be set");
    char base_url[1024];
    snprintf(base_url, sizeof(base_url), "%s/fixtures/vertex_chat", mock_base);
    LITERLLMDefaultClient* client = literllm_create_client("test-key", base_url, (uint64_t)-1, (uint32_t)-1, NULL);
    assert(client != NULL && "failed to create client");
    LITERLLMChatCompletionResponse* result = literllm_default_client_chat(client, chat_completion_request_handle);
    assert(result != NULL && "expected call to succeed");
    char* choices = literllm_chat_completion_response_choices(result);
    char* choices_json = literllm_chat_completion_response_choices(result);
    assert(choices_json != NULL);
    char* choices_0_json = alef_json_array_get_index(choices_json, 0);
    char* message_json = alef_json_get_object(choices_0_json, "message");
    char* choices_0_message_content = alef_json_get_string(message_json, "content");
    char* choices_0_finish_reason = alef_json_get_string(choices_0_json, "finish_reason");
    char* model = literllm_chat_completion_response_model(result);
    LITERLLMUsage* usage_handle = literllm_chat_completion_response_usage(result);
    assert(usage_handle != NULL);
    uint64_t usage_total_tokens = literllm_usage_total_tokens(usage_handle);
    {
        /* count_equals: count elements in array */
        assert(choices != NULL && "expected non-null collection JSON");
        int elem_count = alef_json_array_count(choices);
        assert(elem_count == 1 && "expected 1 elements");
    }
    assert(str_trim_eq(choices_0_message_content, "Hello!") == 0 && "equals assertion failed");
    assert(str_trim_eq(choices_0_finish_reason, "stop") == 0 && "equals assertion failed");
    assert(str_trim_eq(model, "gemini-2.0-flash") == 0 && "equals assertion failed");
    assert(usage_total_tokens == 13 && "equals assertion failed");
    literllm_free_string(choices);
    free(choices_0_message_content);
    free(choices_0_finish_reason);
    literllm_free_string(model);
    literllm_usage_free(usage_handle);
    free(message_json);
    free(choices_0_json);
    literllm_free_string(choices_json);
    literllm_chat_completion_response_free(result);
    literllm_chat_completion_request_free(chat_completion_request_handle);
    literllm_default_client_free(client);
}

